            "B\", C + 1) + \",\" + group + \"B2\", group) +\r\n\r\n                    Convolution(C +" +
            " 2, group + \"CM\", DIV8(outputChannels), 1, 1, 1, 1, 0, 0) +\r\n                   " +
            " BatchNorm(C + 2, In(\"C\", C + 2)));\r\n            }\r\n            else\r\n          " +
            "  {\r\n                blocks.Add(\r\n                    Convolution(C, inputs, hid" +
            "denDim, 1, 1, 1, 1, 0, 0) +\r\n                    BatchNormActivation(C, In(\"C\", " +
            "C), activation) +\r\n                    DepthwiseConvolution(C + 1, In(\"B\", C), 1" +
            ", 3, 3, stride, stride, 1, 1) +\r\n                    (expandRatio > 1 ? BatchNor" +
            "mActivationDropout(C + 1, In(\"DC\", C + 1), activation) : BatchNormActivation(C +" +
            " 1, In(\"DC\", C + 1), activation)) +\r\n                    Convolution(C + 2, In(\"" +
            "B\", C + 1), DIV8(outputChannels), 1, 1, 1, 1, 0, 0) +\r\n                    Batch" +
            "Norm(C + 2, In(\"C\", C + 2)));\r\n            }\r\n\r\n            if (identity)\r\n     " +
            "       {\r\n                blocks.Add(\r\n                    DropPathAdd(A, In(\"B\"" +
            ", C + 2) + \",\" + inputs));\r\n            }\r\n\r\n            return blocks;\r\n       " +
            " }\r\n\r\n\r\n        public static string InvertedResidual(UInt A, UInt C, UInt chann" +
            "els, UInt kernel = 3, UInt pad = 1, bool subsample = false, UInt shuffle = 2, bo" +
            "ol se = false, Activations activation = Activations.HardSwish)\r\n        {\r\n     " +
            "       if (subsample)\r\n            {\r\n                return\r\n                  " +
            "  Convolution(C, In(\"CC\", A), channels, 1, 1, 1, 1, 0, 0) +\r\n                   " +
            " BatchNormActivation(C + 1, In(\"C\", C), activation) +\r\n                    Depth" +
            "wiseConvolution(C + 1, In(\"B\", C + 1), 1, kernel, kernel, 1, 1, pad, pad) +\r\n   " +
            "                 Resampling(C + 1, In(\"DC\", C + 1)) +\r\n                    Batch" +
            "Norm(C + 2, In(\"R\", C + 1)) +\r\n                    Convolution(C + 2, In(\"B\", C " +
            "+ 2), channels, 1, 1, 1, 1, 0, 0) +\r\n                    BatchNormActivation(C +" +
            " 3, In(\"C\", C + 2), activation) +\r\n                    DepthwiseConvolution(C + " +
            "3, In(\"CC\", A), 1, kernel, kernel, 1, 1, pad, pad) +\r\n                    Resamp" +
            "ling(C + 3, In(\"DC\", C + 3)) +\r\n                    BatchNorm(C + 4, In(\"R\", C +" +
            " 3)) +\r\n                    Convolution(C + 4, In(\"B\", C + 4), channels, 1, 1, 1" +
            ", 1, 0, 0) +\r\n                    BatchNormActivation(C + 5, In(\"C\", C + 4), act" +
            "ivation) +\r\n                    Concat(A + 1, In(\"B\", C + 5) + \",\" + In(\"B\", C +" +
            " 3));\r\n            }\r\n            else\r\n            {\r\n                var group" +
            "CH = In(\"CHATT\", C + 3); // Channel Attention\r\n                var groupSP = In(" +
            "\"SPATT\", C + 3); // Spatial Attention\r\n                var strSE = se ?\r\n       " +
            "             GlobalAvgPooling(In(\"B\", C + 3), groupCH) +\r\n                    Co" +
            "nvolution(1, groupCH + \"GAP\", DIV8(channels), 1, 1, 1, 1, 0, 0, false, groupCH) " +
            "+\r\n                    BatchNormActivation(1, groupCH + In(\"C\", 1), activation, " +
            "groupCH) +\r\n                    GlobalMaxPooling(In(\"B\", C + 3), groupCH) +\r\n   " +
            "                 Convolution(2, groupCH + \"GMP\", DIV8(channels), 1, 1, 1, 1, 0, " +
            "0, false, groupCH) +\r\n                    BatchNormActivation(2, groupCH + In(\"C" +
            "\", 2), activation, groupCH) +\r\n                    Add(1, In(groupCH + \"B\", 1) +" +
            " \",\" + In(groupCH + \"B\", 2), groupCH) +\r\n                    Convolution(3, grou" +
            "pCH + \"A1\", DIV8(channels), 1, 1, 1, 1, 0, 0, false, groupCH) +\r\n               " +
            "     BatchNormActivation(3, groupCH + In(\"C\", 3), Activations.HardSigmoid, group" +
            "CH) +\r\n                    Multiply(In(\"B\", C + 3) + \",\" + In(groupCH + \"B\", 3)," +
            " groupCH) +\r\n                    ReductionAvg(1, groupCH + \"CM\", groupSP) +\r\n   " +
            "                 ReductionMax(1, groupCH + \"CM\", groupSP) +\r\n                   " +
            " Concat(1, In(groupSP + \"RAVG\", 1) + \",\" + In(groupSP + \"RMAX\", 1), groupSP) +\r\n" +
            "                    Convolution(1, groupSP + In(\"CC\", 1), 1, 7, 7, 1, 1, 3, 3, f" +
            "alse, groupSP) +\r\n                    BatchNormActivation(1, groupSP + In(\"C\", 1" +
            "), Activations.HardSigmoid, groupSP) +\r\n                    Multiply(groupCH + \"" +
            "CM,\" + groupSP + In(\"B\", 1), groupSP) +\r\n                    Concat(A + 1, In(\"L" +
            "CS\", A) + \",\" + groupSP + \"CM\") :\r\n                    Concat(A + 1, In(\"LCS\", A" +
            ") + \",\" + In(\"B\", C + 3));\r\n\r\n                return\r\n                    Shuffl" +
            "e(A, In(\"CC\", A), shuffle) +\r\n                    ChannelSplit(A, In(\"SH\", A), 2" +
            ", 1, \"L\") + ChannelSplit(A, In(\"SH\", A), 2, 2, \"R\") +\r\n                    Convo" +
            "lution(C, In(\"RCS\", A), channels, 1, 1, 1, 1, 0, 0) +\r\n                    Batch" +
            "NormActivation(C + 1, In(\"C\", C), activation) +\r\n                    DepthwiseCo" +
            "nvolution(C + 1, In(\"B\", C + 1), 1, kernel, kernel, 1, 1, pad, pad) +\r\n         " +
            "           BatchNorm(C + 2, In(\"DC\", C + 1)) +\r\n                    Convolution(" +
            "C + 2, In(\"B\", C + 2), channels, 1, 1, 1, 1, 0, 0) +\r\n                    BatchN" +
            "ormActivation(C + 3, In(\"C\", C + 2), activation) +\r\n                    strSE;\r\n" +
            "            }\r\n        }\r\n\r\n        public static string AugmentedInvertedResidu" +
            "al(UInt A, UInt C, UInt channels, UInt kernel = 3, UInt pad = 1, bool subsample " +
            "= false, UInt shuffle = 2, bool se = false, Activations activation = Activations" +
            ".HardSwish)\r\n        {\r\n            if (subsample)\r\n            {\r\n             " +
            "   return\r\n                    Convolution(C, In(\"CC\", A), channels, 1, 1, 1, 1," +
            " 0, 0) +\r\n                    BatchNormActivation(C + 1, In(\"C\", C), activation)" +
            " +\r\n                    DepthwiseConvolution(C + 1, In(\"B\", C + 1), 1, kernel, k" +
            "ernel, 1, 1, pad, pad) +\r\n                    Resampling(C + 1, In(\"DC\", C + 1))" +
            " +\r\n                    BatchNorm(C + 2, In(\"R\", C + 1)) +\r\n                    " +
            "Convolution(C + 2, In(\"B\", C + 2), channels, 1, 1, 1, 1, 0, 0) +\r\n              " +
            "      BatchNormActivation(C + 3, In(\"C\", C + 2), activation) +\r\n                " +
            "    DepthwiseConvolution(C + 3, In(\"CC\", A), 1, kernel, kernel, 1, 1, pad, pad) " +
            "+\r\n                    Resampling(C + 3, In(\"DC\", C + 3)) +\r\n                   " +
