            "B\", C + 4), channels, 1, 1, 1, 1, 0, 0) +\r\n                    BatchNormActivati" +
            "on(C + 5, In(\"C\", C + 4), activation) +\r\n                    Concat(A + 1, In(\"B" +
            "\", C + 5) + \",\" + In(\"B\", C + 3));\r\n            }\r\n            else\r\n           " +
            " {\r\n                var groupCH = In(\"CHATT\", C + 3); // Channel Attention\r\n    " +
