            "1, kernel, kernel, 1, 1, pad, pad) +\r\n                    BatchNorm(C + 2, In(\"D" +
            "C\", C + 1)) +\r\n                    ChannelSplit(A, In(\"B\", C + 2), 2, 1, \"L1\") +" +
            " ChannelSplit(A, In(\"B\", C + 2), 2, 2, \"R1\") +\r\n                    ChannelSplit" +
            "(A, In(\"CSRL\", A), 2, 1, \"L2\") + ChannelSplit(A, In(\"CSRL\", A), 2, 2, \"R2\") +\r\n " +
            "                   Concat(A, In(\"L1CS\", A) + \",\" + In(\"L2CS\", A), \"L\") +\r\n      " +
