            "         Convolution(C + 2, In(\"RCC\", A), channels, 1, 1, 1, 1, 0, 0) +\r\n       " +
            "             BatchNormActivation(C + 3, In(\"C\", C + 2), activation) +\r\n         " +
            "           strSE;\r\n            }\r\n        }\r\n\r\n        internal static string Ge" +
            "nerate(ScriptParameters p)\r\n        {\r\n            var net =\r\n                \"[" +
            "\" + p.ModelName + \"]\" + nwl +\r\n                \"Dataset=\" + to_string(p.Dataset)" +
            " + nwl +\r\n                \"Dim=\" + to_string(p.C) + \",\" + to_string(p.H) + \",\" +" +
            " to_string(p.W) + nwl +\r\n                ((p.PadH > 0 || p.PadW > 0) ? (!p.Mirro" +
            "rPad ? \"ZeroPad=\" + to_string(p.PadH) + \",\" + to_string(p.PadW) + nwl : \"MirrorP" +
            "ad=\" + to_string(p.PadH) + \",\" + to_string(p.PadW) + nwl) : \"\") +\r\n             " +
            "   ((p.PadH > 0 || p.PadW > 0) ? \"RandomCrop=Yes\" + nwl : \"\") +\r\n               " +
            " \"WeightsFiller=\" + to_string(p.WeightsFiller) + (p.WeightsFillerModeVisible ? \"" +
            "(\" + p.WeightsFillerMode.ToString() + \",\" + to_string(p.WeightsGain) + \")\" : \"\")" +
            " + (p.WeightsGainVisible && !p.WeightsFillerModeVisible ? \"(\" + to_string(p.Weig" +
            "htsGain) + \")\" : \"\") + (p.WeightsScaleVisible ? \"(\" + to_string(p.WeightsScale) " +
            "+ \")\" : \"\") + nwl +\r\n                (p.WeightsLRM != 1 ? \"WeightsLRM=\" + to_str" +
            "ing(p.WeightsLRM) + nwl : \"\") +\r\n                (p.WeightsWDM != 1 ? \"WeightsWD" +
            "M=\" + to_string(p.WeightsWDM) + nwl : \"\") +\r\n                (p.HasBias ? \"Biase" +
            "sFiller=\" + to_string(p.BiasesFiller) + (p.BiasesFillerModeVisible ? \"(\" + p.Bia" +
            "sesFillerMode.ToString() + \",\" + to_string(p.BiasesGain) + \")\" : \"\") + (p.Biases" +
            "GainVisible && !p.BiasesFillerModeVisible ? \"(\" + to_string(p.BiasesGain) + \")\" " +
            ": \"\") + (p.BiasesScaleVisible ? \"(\" + to_string(p.BiasesScale) + \")\" : \"\") + nwl" +
            " +\r\n                (p.BiasesLRM != 1 ? \"BiasesLRM=\" + to_string(p.BiasesLRM) + " +
            "nwl : \"\") +\r\n                (p.BiasesWDM != 1 ? \"BiasesWDM=\" + to_string(p.Bias" +
            "esWDM) + nwl : \"\") : \"Biases=No\" + nwl) +\r\n                (p.DropoutVisible ? \"" +
            "Dropout=\" + to_string(p.Dropout) + nwl : \"\") +\r\n                (p.DepthDropVisi" +
            "ble ? \"DepthDrop=\" + to_string(p.DepthDrop) + nwl : \"\") +\r\n                (p.De" +
            "pthDropVisible ? \"FixedDepthDrop=\" + to_string(p.FixedDepthDrop) + nwl : \"\") +\r\n" +
            "                \"Scaling=\" + to_string(p.BatchNormScaling) + nwl +\r\n            " +
            "    \"Momentum=\" + to_string(p.BatchNormMomentum) + nwl +\r\n                \"Eps=\"" +
            " + to_string(p.BatchNormEps) + nwl + nwl;\r\n\r\n            var blocks = new List<s" +
            "tring>();\r\n\r\n            switch (p.Script)\r\n            {\r\n                case " +
            "Scripts.augshufflenet:\r\n                    {\r\n                        var chann" +
            "els = DIV8(p.Width * 16);\r\n\r\n                        net +=\r\n                   " +
            "         Convolution(1, \"Input\", channels, 3, 3, p.StrideHFirstConv, p.StrideWFi" +
            "rstConv, 1, 1) +\r\n                            BatchNormActivation(1, \"C1\", p.Act" +
            "ivation) +\r\n                            Convolution(2, \"B1\", channels, 1, 1, 1, " +
            "1, 0, 0) +\r\n                            BatchNormActivation(2, \"C2\", p.Activatio" +
            "n) +\r\n                            DepthwiseConvolution(3, \"B2\", 1, 3, 3, 1, 1, 1" +
            ", 1) +\r\n                            BatchNorm(3, \"DC3\") +\r\n                     " +
            "       Convolution(4, \"B3\", channels, 1, 1, 1, 1, 0, 0) +\r\n                     " +
            "       BatchNormActivation(4, \"C4\", p.Activation) +\r\n                           " +
            " Convolution(5, \"B1\", channels, 1, 1, 1, 1, 0, 0) +\r\n                           " +
            " Concat(1, \"C5,B4\");\r\n\r\n                        var C = 6ul;\r\n                  " +
            "      var A = 1ul;\r\n                        var subsample = false;\r\n            " +
            "            foreach (var rec in p.ShuffleNet)\r\n                        {\r\n      " +
            "                      if (subsample)\r\n                            {\r\n           " +
            "                     channels *= 2;\r\n                                net += Augm" +
            "entedInvertedResidual(A++, C, channels, rec.Kernel, rec.Pad, true, rec.Shuffle, " +
            "rec.SE, p.Activation);\r\n                                C += 5;\r\n               " +
            "             }\r\n                            for (var n = 0ul; n < rec.Iterations" +
