            "e, rec.SE, p.Activation);\r\n                                C += 3;\r\n            " +
            "                }\r\n                            subsample = true;\r\n              " +
            "          }\r\n\r\n                        net +=\r\n                            Convo" +
            "lution(C, In(\"CC\", A), p.Classes, 1, 1, 1, 1, 0, 0) +\r\n                         " +
