            " In(\"B\", C + 1), DIV8(p.GrowthRate), 3, 3, 1, 1, 1, 1) +\r\n                      " +
            "                  (p.Dropout > 0 ? Dropout(C + 1, In(\"C\", C + 1)) + Concat(CC + " +
            "1, In(\"CC\", CC) + \",\" + In(\"D\", C + 1)) : Concat(CC + 1, In(\"CC\", CC) + \",\" + In" +
            "(\"C\", C + 1))));\r\n\r\n                                    C += 2;\r\n               " +
            "                 }\r\n                                else\r\n                      " +
            "          {\r\n                                    blocks.Add(\r\n                  " +
            "                      BatchNormActivation(C, In(\"CC\", CC), p.Activation) +\r\n    " +
            "                                    Convolution(C, In(\"B\", C), DIV8(p.GrowthRate" +
            "), 3, 3, 1, 1, 1, 1) +\r\n                                        (p.Dropout > 0 ?" +
            " Dropout(C, In(\"C\", C)) + Concat(CC + 1, In(\"CC\", CC) + \",\" + In(\"D\", C)) : Conc" +
            "at(CC + 1, In(\"CC\", CC) + \",\" + In(\"C\", C))));\r\n\r\n                              " +
            "      C++;\r\n                                }\r\n\r\n                               " +
            " CC++;\r\n                                channels += DIV8(p.GrowthRate);\r\n       " +
            "                     }\r\n\r\n                            if (g < p.Groups)\r\n       " +
            "                     {\r\n                                channels = DIV8((UInt)Sy" +
            "stem.Math.Floor(2.0 * channels * p.Compression));\r\n\r\n                           " +
            "     if (p.Dropout > 0)\r\n                                    blocks.Add(\r\n      " +
            "                                  Convolution(C, In(\"CC\", CC), channels, 1, 1, 1" +
            ", 1, 0, 0) +\r\n                                        Dropout(C, In(\"C\", C)) +\r\n" +
            "                                        AvgPooling(g, In(\"D\", C), \"2,2\", \"2,2\", " +
            "\"0,0\"));\r\n                                else\r\n                                " +
            "    blocks.Add(\r\n                                        Convolution(C, \"CC\" + t" +
            "o_string(CC), channels, 1, 1, 1, 1, 0, 0) +\r\n                                   " +
