            "tivation(C, In(\"P\", g), p.Activation) +\r\n                                       " +
            " Convolution(C, In(\"B\", C), DIV8(4 * p.GrowthRate), 1, 1, 1, 1, 0, 0) +\r\n       " +
            "                                 BatchNormActivation(C + 1, In(\"C\", C), p.Activa" +
            "tion) +\r\n                                        Convolution(C + 1, In(\"B\", C + " +
            "1), DIV8(p.GrowthRate), 3, 3, 1, 1, 1, 1) +\r\n                                   " +
            "     (p.Dropout > 0 ? Dropout(C + 1, In(\"C\", C + 1)) + Concat(CC, In(\"B\", C) + \"" +
            ",\" + In(\"D\", C + 1)) : Concat(CC, In(\"B\", C) + \",\" + In(\"C\", C + 1))));\r\n\r\n     " +
            "                               C += 2;\r\n                                }\r\n     " +
            "                           else\r\n                                {\r\n            " +
            "                        blocks.Add(\r\n                                        Bat" +
            "chNormActivation(C, In(\"P\", g), p.Activation) +\r\n                               " +
