            "iptsDirectory, \"bin\", Mode, Framework);\r\n\r\n        static void Main()\r\n        {" +
            "\r\n            var script = Generate(new ScriptParameters()\r\n            {\r\n     " +
            "           Script = Scripts.resnet,\r\n                Activation = Activations.Re" +
